        // Get shipment by tracking number (customers)
        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments
                .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
            return shipment is null ? Results.NotFound() : Results.Ok(shipment);
        });

        // Create a new shipment (dispatchers)
        group.MapPost("/", async (CreateShipmentRequest request, ApplicationDbContext db) =>
        {
            var shipment = new Shipment
            {
                TrackingNumber = GenerateTrackingNumber(),
                Origin = request.Origin,
                Destination = request.Destination,
                Status = ShipmentStatus.Pending,
                ShippedDate = DateTime.UtcNow,
                EstimatedDelivery = DateTime.UtcNow.AddDays(request.EstimatedDays),
                RecipientName = request.RecipientName,
                RecipientEmail = request.RecipientEmail
            };

            db.Shipments.Add(shipment);
            await db.SaveChangesAsync();
            return Results.Created($"/api/shipments/{shipment.Id}", shipment);
        });

        // Update shipment status (dispatchers)
        group.MapPut("/{id:int}/status", async (int id, UpdateStatusRequest request, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null) return Results.NotFound();

            shipment.Status = request.Status;
            await db.SaveChangesAsync();
            return Results.Ok(shipment);
        });
    }

    private static string GenerateTrackingNumber()
    {
        return $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(10000, 99999)}";
    }
}

public record CreateShipmentRequest(
    string Origin,
    string Destination,
    int EstimatedDays,
    string RecipientName,
    string RecipientEmail);

public record UpdateStatusRequest(ShipmentStatus Status);

