@page "/shipments"
@using ShipmentTracker.Client.Models
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@inject HttpClient Http

<PageTitle>Shipment Dashboard</PageTitle>

<h2 class="mb-4">📦 Shipment Dashboard</h2>

<div class="row mb-3">
    <div class="col-md-4">
        <input type="text" class="form-control" placeholder="Filter by destination..."
               @bind="filterText" @bind:event="oninput" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="statusFilter">
            <option value="">All Statuses</option>
            @foreach (var status in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@status">@status</option>
            }
        </select>
    </div>
    <div class="col-md-3">
        <button class="btn btn-primary" @onclick="ShowCreateForm">
            ➕ New Shipment
        </button>
    </div>
</div>

@if (showCreateForm)
{
    <div class="card mb-4">
        <div class="card-header">Create New Shipment</div>
        <div class="card-body">
            <EditForm Model="newShipment" OnValidSubmit="CreateShipment" FormName="createShipment">
                <DataAnnotationsValidator />
                <div class="row g-3">
                    <div class="col-md-6">
                        <label class="form-label">Origin</label>
                        <InputText class="form-control" @bind-Value="newShipment.Origin" />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Destination</label>
                        <InputText class="form-control" @bind-Value="newShipment.Destination" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Recipient Name</label>
                        <InputText class="form-control" @bind-Value="newShipment.RecipientName" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Recipient Email</label>
                        <InputText class="form-control" @bind-Value="newShipment.RecipientEmail" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Estimated Days</label>
                        <InputNumber class="form-control" @bind-Value="newShipment.EstimatedDays" />
                    </div>
                </div>
                <div class="mt-3">
                    <button type="submit" class="btn btn-success me-2">Create</button>
                    <button type="button" class="btn btn-secondary" @onclick="() => showCreateForm = false">Cancel</button>
                </div>
                <ValidationSummary />
            </EditForm>
        </div>
    </div>
}

@if (shipments == null)
{
    <p><em>Loading shipments...</em></p>
}
else if (!FilteredShipments.Any())
{
    <p class="text-muted">No shipments match your criteria.</p>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Recipient</th>
                    <th>Status</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var s in FilteredShipments)
                {
                    <tr>
                        <td><code>@s.TrackingNumber</code></td>
                        <td>@s.Origin</td>
                        <td>@s.Destination</td>
                        <td>@s.RecipientName</td>
                        <td><span class="badge @GetStatusBadge(s.Status)">@s.Status</span></td>
                        <td>@s.EstimatedDelivery.ToString("MMM dd, yyyy")</td>
                        <td>
                            <select class="form-select form-select-sm" style="width: auto; display: inline-block;"
                                    value="@s.Status" @onchange="(e) => UpdateStatus(s, e)">
                                @foreach (var status in Enum.GetValues<ShipmentStatus>())
                                {
                                    <option value="@status">@status</option>
                                }
                            </select>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private List<ShipmentDto>? shipments;
    private string filterText = "";
    private string statusFilter = "";
    private bool showCreateForm;
    private CreateShipmentModel newShipment = new();

    private IEnumerable<ShipmentDto> FilteredShipments =>
        (shipments ?? []).Where(s =>
            (string.IsNullOrWhiteSpace(filterText) ||
             s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase)) &&
            (string.IsNullOrWhiteSpace(statusFilter) ||
             s.Status.ToString() == statusFilter));

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        shipments = await Http.GetFromJsonAsync<List<ShipmentDto>>("/api/shipments");
    }

    private void ShowCreateForm()
    {
        newShipment = new CreateShipmentModel();
        showCreateForm = true;
    }

    private async Task CreateShipment()
    {
        var response = await Http.PostAsJsonAsync("/api/shipments", new
        {
            newShipment.Origin,
            newShipment.Destination,
            newShipment.EstimatedDays,
            newShipment.RecipientName,
            newShipment.RecipientEmail
        });

        if (response.IsSuccessStatusCode)
        {
            showCreateForm = false;
            await LoadShipments();
        }
    }

    private async Task UpdateStatus(ShipmentDto shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            var response = await Http.PutAsJsonAsync($"/api/shipments/{shipment.Id}/status", new { Status = newStatus });
            if (response.IsSuccessStatusCode)
            {
                shipment.Status = newStatus;
            }
        }
    }

    private static string GetStatusBadge(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Exception => "bg-danger",
        _ => "bg-secondary"
    };

    private class CreateShipmentModel
    {
        public string Origin { get; set; } = "";
        public string Destination { get; set; } = "";
        public string RecipientName { get; set; } = "";
        public string RecipientEmail { get; set; } = "";
        public int EstimatedDays { get; set; } = 7;
    }
}

